  sessionParticipant?: Prisma.SessionParticipantOmit
  candidateSlot?: Prisma.CandidateSlotOmit
  sessionMessage?: Prisma.SessionMessageOmit
  outboundDraft?: Prisma.OutboundDraftOmit
  approvalBundle?: Prisma.ApprovalBundleOmit
  styleEdit?: Prisma.StyleEditOmit
  auditEvent?: Prisma.AuditEventOmit
  followUpPolicy?: Prisma.FollowUpPolicyOmit
  followUpAttempt?: Prisma.FollowUpAttemptOmit
  workflowRun?: Prisma.WorkflowRunOmit
  outboxCommand?: Prisma.OutboxCommandOmit
  inboxReceipt?: Prisma.InboxReceiptOmit
